package edu.tcd.library.admin.service;

import edu.tcd.library.admin.entity.Room;

import java.util.List;

/**
 * Service interface for room cache management
 */
public interface RoomService {

    /**
     * get all rooms which is generated by current user(librarian)
     *
     * @return List<Room>
     */
    List<Room> listAll();

    /**
     * add rooms
     *
     * @param rooms rooms information
     * @return add result
     */
    Boolean addRooms(List<Room> rooms);
}
